335→          },
336→          {
337→            label: 'Copy',
338→            shortcut: (
339→              <Kbd
340→                keys={[
341→                  '⌘',
342→                  'C',
343→                ]}
344→              />
345→            ),
346→            onClick: handleCopy,
347→          },
348→        ],
349→      },
350→      {
351→        title: 'Organize',
