378→                ]}
379→              />
380→            ),
381→            onClick: handleDelete,
382→          },
383→        ],
384→      },
385→    ],
386→    [
387→      selectedEntry?.pinned,
388→      handlePaste,
389→      handleCopy,
390→      handleTogglePin,
391→      handleDelete,
392→    ],
393→  );
394→
395→  const activeDescendantId =
396→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
397→
398→  return (
399→    <>
400→      <SearchBar
401→        value={query}
402→        onChange={handleQueryChange}
403→        placeholder="Search Clipboard History..."
404→        activeDescendantId={activeDescendantId}
405→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
406→        dropdown={
407→          <SearchDropdown
408→            sections={FILTER_SECTIONS}
409→            value={filterValue}
410→            onChange={handleFilterChange}
411→          />
412→        }
413→      />
414→      <div className="command-palette__body">
415→        <div className="command-palette__list-container">
416→          {totalItemCount === 0 ? (
417→            <EmptyState
418→              icon={<SearchEmptyIcon />}
419→              title="No Results"
420→              description="Try a different search term"
421→            />
422→          ) : (
423→            <List
424→              itemCount={totalItemCount}
425→              onActiveIndexChange={handleActiveIndexChange}
426→              onAction={handleAction}
427→            >
428→              {(() => {
429→                let globalIndex = 0;
430→
431→                const sections: ReactNode[] = [];
432→
433→                if (pinnedItems.length > 0) {
434→                  sections.push(
435→                    <ListSection key="pinned" title="Pinned">
436→                      {pinnedItems.map(entry => {
437→                        const idx = globalIndex++;
438→                        return (
439→                          <ListItem
440→                            key={entry.id}
441→                            index={idx}
442→                            icon={renderClipboardIcon(entry)}
443→                            title={truncateContent(entry.content, 60)}
444→                            subtitle={entry.sourceApp}
445→                            accessories={[
446→                              {
447→                                text: formatRelativeDate(entry.copiedAt, now),
448→                                tooltip: entry.copiedAt.toLocaleString(),
449→                              },
450→                            ]}
451→                          />
452→                        );
453→                      })}
454→                    </ListSection>,
455→                  );
456→                }
457→
458→                if (recentItems.length > 0) {
459→                  sections.push(
460→                    <ListSection key="recent" title="Recent">
461→                      {recentItems.map(entry => {
462→                        const idx = globalIndex++;
463→                        return (
464→                          <ListItem
465→                            key={entry.id}
466→                            index={idx}
467→                            icon={renderClipboardIcon(entry)}
468→                            title={truncateContent(entry.content, 60)}
469→                            subtitle={entry.sourceApp}
470→                            accessories={[
471→                              {
472→                                text: formatRelativeDate(entry.copiedAt, now),
473→                                tooltip: entry.copiedAt.toLocaleString(),
474→                              },
475→                            ]}
476→                          />
477→                        );
478→                      })}
479→                    </ListSection>,
480→                  );
481→                }
482→
483→                return sections;
484→              })()}
485→            </List>
486→          )}
487→        </div>
488→      </div>
489→      <ActionPanel
