  66→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
  67→  if (!query) return colors;
  68→  const lower = query.toLowerCase();
  69→  return colors.filter(
  70→    c =>
  71→      c.title.toLowerCase().includes(lower) ||
  72→      c.subtitle?.toLowerCase().includes(lower),
  73→  );
  74→}
  75→
  76→function flattenItems(sections: SectionData[]): ListItemData[] {
  77→  return sections.flatMap(s => s.items);
  78→}
