 1→const MINUTE = 60_000;
 2→const HOUR = 3_600_000;
 3→
 4→function startOfDay(date: Date): Date {
 5→  return new Date(date.getFullYear(), date.getMonth(), date.getDate());
 6→}
 7→
 8→function calendarDaysDiff(date: Date, now: Date): number {
 9→  const dateDay = startOfDay(date).getTime();
10→  const nowDay = startOfDay(now).getTime();
11→  return Math.round((nowDay - dateDay) / 86_400_000);
12→}
13→
14→export function formatRelativeDate(date: Date, now: Date = new Date()): string {
15→  const diff = now.getTime() - date.getTime();
16→
17→  if (diff < 0) {
18→    return formatAbsoluteDate(date, now);
19→  }
20→
21→  if (diff < MINUTE) {
22→    return 'Just now';
23→  }
24→
25→  if (diff < HOUR) {
26→    const minutes = Math.floor(diff / MINUTE);
27→    return `${minutes} ${minutes === 1 ? 'minute' : 'minutes'} ago`;
28→  }
29→
30→  const daysDiff = calendarDaysDiff(date, now);
31→
32→  if (daysDiff === 0) {
33→    const hours = Math.floor(diff / HOUR);
34→    return `${hours} ${hours === 1 ? 'hour' : 'hours'} ago`;
35→  }
36→
37→  if (daysDiff === 1) {
38→    return 'Yesterday';
39→  }
40→
41→  if (daysDiff < 7) {
42→    return `${daysDiff} days ago`;
43→  }
44→
45→  return formatAbsoluteDate(date, now);
46→}
47→
48→function formatAbsoluteDate(date: Date, now: Date): string {
49→  const sameYear = date.getFullYear() === now.getFullYear();
50→  const month = date.toLocaleDateString('en-US', { month: 'short' });
51→  const day = date.getDate();
52→
53→  if (sameYear) {
54→    return `${month} ${day}`;
55→  }
56→
57→  return `${month} ${day}, ${date.getFullYear()}`;
58→}
